import { EntitySchema } from "typeorm";

export type ConversationChannel = "dashboard" | "telegram" | "whatsapp";
export type ConversationTerminationReason =
  | "model_final"
  | "max_turns"
  | "token_cap"
  | "points_budget_exhausted"
  | "user_cancelled"
  | "error";

export interface ConversationEntity {
  id: string;
  userId: string;
  channel: ConversationChannel;
  startedAt: Date;
  endedAt: Date | null;
  turnCount: number;
  totalTokensIn: number;
  totalTokensOut: number;
  totalCostUsd: string;
  terminationReason: ConversationTerminationReason | null;
  toolCallCount: number;
  model: string | null;
}

export const ConversationEntitySchema = new EntitySchema<ConversationEntity>({
  name: "Conversation",
  tableName: "conversations",
  columns: {
    id: { type: "varchar", length: 64, primary: true },
    userId: { name: "user_id", type: "varchar", length: 64 },
    channel: { type: "varchar", length: 16 },
    startedAt: { name: "started_at", type: "timestamptz" },
    endedAt: { name: "ended_at", type: "timestamptz", nullable: true },
    turnCount: { name: "turn_count", type: "integer", default: 0 },
    totalTokensIn: { name: "total_tokens_in", type: "integer", default: 0 },
    totalTokensOut: { name: "total_tokens_out", type: "integer", default: 0 },
    totalCostUsd: { name: "total_cost_usd", type: "numeric", precision: 14, scale: 6 },
    terminationReason: { name: "termination_reason", type: "varchar", length: 32, nullable: true },
    toolCallCount: { name: "tool_call_count", type: "integer", default: 0 },
    model: { type: "varchar", length: 255, nullable: true },
  },
});

import { randomUUID } from "crypto";
import { getApplicationDataSource, isApplicationDatabaseConfigured } from "../../db/applicationDataSource.js";
import type { ConversationChannel, ConversationTerminationReason } from "../../db/entities/ConversationEntity.js";
import type { TurnRole } from "../../db/entities/ConversationTurnEntity.js";
import { unwrapMutationRows } from "../dbUtils.js";

/**
 * Conversation store — Phase 5, task 5.8.
 *
 * Spec: design.md §4.11; C2.1, C2.2, C2.3, NFR6.2, NFR6.4.
 *
 * Persists every conversation turn, tool call, and conversation summary.
 * `appendToolCall` writes the audit row BEFORE the handler executes (NFR6.4).
 */

export interface ConversationRecord {
  id: string;
  userId: string;
  channel: ConversationChannel;
  startedAt: string;
  endedAt: string | null;
  turnCount: number;
  totalTokensIn: number;
  totalTokensOut: number;
  totalCostUsd: number;
  terminationReason: ConversationTerminationReason | null;
  toolCallCount: number;
  model: string | null;
}

export interface TurnRecord {
  conversationId: string;
  turnIndex: number;
  role: TurnRole;
  content: unknown;
  model: string | null;
  tokensIn: number;
  tokensOut: number;
  costUsd: number;
  latencyMs: number;
  createdAt: string;
}

export interface AppendTurnInput {
  role: TurnRole;
  content: unknown;
  model?: string | null;
  tokensIn?: number;
  tokensOut?: number;
  costUsd?: number;
  latencyMs?: number;
}

// ---------------------------------------------------------------------------
// Create / load
// ---------------------------------------------------------------------------

export async function createConversation(input: {
  userId: string;
  channel: ConversationChannel;
  model?: string | null;
}): Promise<ConversationRecord> {
  if (!isApplicationDatabaseConfigured()) {
    throw new Error("createConversation requires the application database");
  }
  const ds = await getApplicationDataSource();
  const id = `conv_${Date.now()}_${randomUUID().slice(0, 8)}`;
  const rows = await ds.query(
    `INSERT INTO conversations
       (id, user_id, channel, started_at, turn_count, total_tokens_in, total_tokens_out,
        total_cost_usd, tool_call_count, model)
     VALUES ($1, $2, $3, NOW(), 0, 0, 0, 0, 0, $4)
     RETURNING id, user_id, channel, started_at, ended_at, turn_count,
               total_tokens_in, total_tokens_out, total_cost_usd,
               termination_reason, tool_call_count, model`,
    [id, input.userId, input.channel, input.model ?? null]
  ) as Array<Record<string, unknown>>;
  return fromRow(rows[0]!);
}

export async function loadConversation(conversationId: string): Promise<ConversationRecord | null> {
  if (!isApplicationDatabaseConfigured()) return null;
  const ds = await getApplicationDataSource();
  const rows = await ds.query(
    `SELECT id, user_id, channel, started_at, ended_at, turn_count,
            total_tokens_in, total_tokens_out, total_cost_usd,
            termination_reason, tool_call_count, model
       FROM conversations WHERE id = $1 LIMIT 1`,
    [conversationId]
  ) as Array<Record<string, unknown>>;
  return rows[0] ? fromRow(rows[0]) : null;
}

// ---------------------------------------------------------------------------
// Turn management
// ---------------------------------------------------------------------------

export async function appendTurn(
  conversationId: string,
  input: AppendTurnInput
): Promise<TurnRecord> {
  if (!isApplicationDatabaseConfigured()) {
    throw new Error("appendTurn requires the application database");
  }
  const ds = await getApplicationDataSource();

  return ds.transaction(async (manager) => {
    // Increment turn_count and get the new index atomically.
    // unwrapMutationRows handles TypeORM's [rows, rowCount] UPDATE RETURNING shape.
    const rawUpdated = await manager.query(
      `UPDATE conversations
          SET turn_count = turn_count + 1,
              total_tokens_in = total_tokens_in + $2,
              total_tokens_out = total_tokens_out + $3,
              total_cost_usd = total_cost_usd + $4
        WHERE id = $1
        RETURNING turn_count`,
      [
        conversationId,
        input.tokensIn ?? 0,
        input.tokensOut ?? 0,
        input.costUsd ?? 0,
      ]
    );
    const updatedRows = unwrapMutationRows<{ turn_count: number }>(rawUpdated);
    if (updatedRows.length === 0) {
      throw new Error(`conversation_not_found: ${conversationId}`);
    }
    const turnIndex = updatedRows[0]!.turn_count - 1;

    const rows = await manager.query(
      `INSERT INTO conversation_turns
         (conversation_id, turn_index, role, content, model,
          tokens_in, tokens_out, cost_usd, latency_ms, created_at)
       VALUES ($1, $2, $3, $4::jsonb, $5, $6, $7, $8, $9, NOW())
       RETURNING conversation_id, turn_index, role, content, model,
                 tokens_in, tokens_out, cost_usd, latency_ms, created_at`,
      [
        conversationId,
        turnIndex,
        input.role,
        JSON.stringify(input.content),
        input.model ?? null,
        input.tokensIn ?? 0,
        input.tokensOut ?? 0,
        input.costUsd ?? 0,
        input.latencyMs ?? 0,
      ]
    ) as Array<Record<string, unknown>>;
    return fromTurnRow(rows[0]!);
  });
}

export async function loadHistory(
  conversationId: string,
  maxTurns = 50
): Promise<TurnRecord[]> {
  if (!isApplicationDatabaseConfigured()) return [];
  const ds = await getApplicationDataSource();
  const rows = await ds.query(
    `SELECT conversation_id, turn_index, role, content, model,
            tokens_in, tokens_out, cost_usd, latency_ms, created_at
       FROM conversation_turns
      WHERE conversation_id = $1
      ORDER BY turn_index ASC
      LIMIT $2`,
    [conversationId, maxTurns]
  ) as Array<Record<string, unknown>>;
  return rows.map(fromTurnRow);
}

// ---------------------------------------------------------------------------
// Finalization
// ---------------------------------------------------------------------------

export async function endConversation(
  conversationId: string,
  reason: ConversationTerminationReason,
  model?: string | null
): Promise<void> {
  if (!isApplicationDatabaseConfigured()) return;
  const ds = await getApplicationDataSource();
  await ds.query(
    `UPDATE conversations
        SET ended_at = NOW(),
            termination_reason = $2,
            model = COALESCE($3, model)
      WHERE id = $1`,
    [conversationId, reason, model ?? null]
  );
}

export async function incrementToolCallCount(conversationId: string): Promise<void> {
  if (!isApplicationDatabaseConfigured()) return;
  const ds = await getApplicationDataSource();
  await ds.query(
    `UPDATE conversations SET tool_call_count = tool_call_count + 1 WHERE id = $1`,
    [conversationId]
  );
}

// ---------------------------------------------------------------------------
// Row mappers
// ---------------------------------------------------------------------------

function fromRow(row: Record<string, unknown>): ConversationRecord {
  return {
    id: String(row["id"]),
    userId: String(row["user_id"]),
    channel: String(row["channel"]) as ConversationChannel,
    startedAt: toIso(row["started_at"]),
    endedAt: row["ended_at"] ? toIso(row["ended_at"]) : null,
    turnCount: Number(row["turn_count"] ?? 0),
    totalTokensIn: Number(row["total_tokens_in"] ?? 0),
    totalTokensOut: Number(row["total_tokens_out"] ?? 0),
    totalCostUsd: Number(row["total_cost_usd"] ?? 0),
    terminationReason: (row["termination_reason"] as ConversationTerminationReason | null) ?? null,
    toolCallCount: Number(row["tool_call_count"] ?? 0),
    model: row["model"] ? String(row["model"]) : null,
  };
}

function fromTurnRow(row: Record<string, unknown>): TurnRecord {
  return {
    conversationId: String(row["conversation_id"]),
    turnIndex: Number(row["turn_index"]),
    role: String(row["role"]) as TurnRole,
    content: row["content"],
    model: row["model"] ? String(row["model"]) : null,
    tokensIn: Number(row["tokens_in"] ?? 0),
    tokensOut: Number(row["tokens_out"] ?? 0),
    costUsd: Number(row["cost_usd"] ?? 0),
    latencyMs: Number(row["latency_ms"] ?? 0),
    createdAt: toIso(row["created_at"]),
  };
}

function toIso(value: unknown): string {
  if (value instanceof Date) return value.toISOString();
  if (typeof value === "string") return new Date(value).toISOString();
  return new Date().toISOString();
}

import { Router } from "express";
import type { Response, NextFunction } from "express";
import type { AuthenticatedRequest } from "../middleware/auth.js";
import { agentChat } from "../services/chat/agentChat.js";
import { loadConversation, loadHistory } from "../services/chat/conversationStore.js";
import { isApplicationDatabaseConfigured } from "../db/applicationDataSource.js";
import { logger } from "../services/logger.js";
import { z } from "zod";

/**
 * Dashboard chat route — Phase 5, task 5.11.
 *
 * Spec: design.md §9.1; D3.1, D3.2.
 *
 * POST /api/chat/messages — send a message, get a reply.
 * GET  /api/chat/conversations/:id — read conversation history.
 * GET  /api/admin/conversations — admin observability (task 5.12).
 *
 * Auth: existing JWT header (cookie auth lands Phase 8).
 * No client-side tool-call interpretation (D3.2).
 */

const router = Router();

type AsyncHandler = (req: AuthenticatedRequest, res: Response, next: NextFunction) => Promise<void>;
function handler(fn: AsyncHandler) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    fn(req, res, next).catch(next);
  };
}

const ChatMessageBodySchema = z.object({
  text: z.string().min(1).max(4000),
  conversationId: z.string().optional(),
});

// ── POST /api/chat/messages ─────────────────────────────────────────────────

router.post(
  "/chat/messages",
  handler(async (req, res) => {
    const userId = res.locals["userId"] as string;
    const parsed = ChatMessageBodySchema.safeParse(req.body);
    if (!parsed.success) {
      res.status(400).json({ error: "invalid_request", details: parsed.error.message });
      return;
    }

    try {
      const result = await agentChat({
        userId,
        text: parsed.data.text,
        channel: "dashboard",
        ...(parsed.data.conversationId ? { conversationId: parsed.data.conversationId } : {}),
      });
      res.json({
        conversationId: result.conversationId,
        replyText: result.replyText,
        terminationReason: result.terminationReason,
        totalCostUsd: result.totalCostUsd,
        turnCount: result.turnCount,
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      logger.error(`chat route error user=${userId}: ${msg}`);
      res.status(500).json({ error: "chat_error", message: "An error occurred processing your message." });
    }
  })
);

// ── GET /api/chat/conversations/:id ─────────────────────────────────────────

router.get(
  "/chat/conversations/:id",
  handler(async (req, res) => {
    const userId = res.locals["userId"] as string;
    const conversationId = String(req.params["id"] ?? "");

    if (!isApplicationDatabaseConfigured()) {
      res.status(503).json({ error: "database_unavailable" });
      return;
    }

    const conv = await loadConversation(conversationId);
    if (!conv || conv.userId !== userId) {
      res.status(404).json({ error: "conversation_not_found" });
      return;
    }

    const turns = await loadHistory(conversationId, 200);
    res.json({ conversation: conv, turns });
  })
);

export default router;

import { apiClient } from "./client";

export interface ChatMessage {
  role: "user" | "assistant";
  content: string;
  createdAt?: string;
}

export interface SendMessageResponse {
  conversationId: string;
  replyText: string;
  terminationReason: string;
  totalCostUsd: number;
  turnCount: number;
}

export interface ConversationTurn {
  conversationId: string;
  turnIndex: number;
  role: string;
  content: unknown;
  model: string | null;
  tokensIn: number;
  tokensOut: number;
  costUsd: number;
  latencyMs: number;
  createdAt: string;
}

export interface ConversationHistory {
  conversation: {
    id: string;
    userId: string;
    channel: string;
    startedAt: string;
    endedAt: string | null;
    turnCount: number;
    totalCostUsd: number;
    terminationReason: string | null;
  };
  turns: ConversationTurn[];
}

export async function sendChatMessage(
  text: string,
  conversationId?: string
): Promise<SendMessageResponse> {
  const res = await apiClient.post<SendMessageResponse>("/chat/messages", {
    text,
    conversationId,
  });
  return res.data;
}

export async function getConversationHistory(
  conversationId: string
): Promise<ConversationHistory> {
  const res = await apiClient.get<ConversationHistory>(
    `/chat/conversations/${conversationId}`
  );
  return res.data;
}

import { useState, useRef, useEffect } from "react";
import { useMutation } from "@tanstack/react-query";
import { MessageCircle, Send, Loader2, AlertCircle, Plus } from "lucide-react";
import { sendChatMessage } from "../api/chat";
import { clsx } from "clsx";

/**
 * Dashboard chat pane — Phase 5, task 5.14.
 *
 * Conversation ID and messages are persisted to localStorage with a 14-day TTL
 * so the user can return to the same conversation across sessions.
 */

const STORAGE_KEY = "chat_session";
const TTL_MS = 14 * 24 * 60 * 60 * 1000; // 14 days

interface StoredSession {
  conversationId: string;
  messages: Message[];
  savedAt: number;
}

function loadSession(): StoredSession | null {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as StoredSession;
    if (Date.now() - parsed.savedAt > TTL_MS) {
      localStorage.removeItem(STORAGE_KEY);
      return null;
    }
    return parsed;
  } catch {
    return null;
  }
}

function saveSession(conversationId: string, messages: Message[]): void {
  try {
    const session: StoredSession = { conversationId, messages, savedAt: Date.now() };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(session));
  } catch {
    // localStorage full — ignore
  }
}

function clearSession(): void {
  localStorage.removeItem(STORAGE_KEY);
}

/**
 * Dashboard chat pane — Phase 5, task 5.14.
 *
 * Spec: design.md §9.1; D3.1, D3.2.
 *
 * Renders streamed or final replies as plain text. No client-side tool-call
 * interpretation (D3.2). Conversation ID is persisted in component state so
 * the same conversation continues across messages in the same session.
 */

interface Message {
  id: string;
  role: "user" | "assistant";
  content: string;
  isError?: boolean;
}

export function Chat() {
  const stored = loadSession();
  const [messages, setMessages] = useState<Message[]>(stored?.messages ?? []);
  const [input, setInput] = useState("");
  const [conversationId, setConversationId] = useState<string | undefined>(stored?.conversationId);
  const bottomRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  // Persist session whenever messages or conversationId change
  useEffect(() => {
    if (conversationId && messages.length > 0) {
      saveSession(conversationId, messages);
    }
  }, [conversationId, messages]);

  const handleNewChat = () => {
    clearSession();
    setMessages([]);
    setConversationId(undefined);
    setInput("");
  };

  const mutation = useMutation({
    mutationFn: ({ text, convId }: { text: string; convId?: string }) =>
      sendChatMessage(text, convId),
    onSuccess: (data) => {
      setConversationId(data.conversationId);
      setMessages((prev) => [
        ...prev,
        {
          id: `assistant-${Date.now()}`,
          role: "assistant",
          content: data.replyText,
        },
      ]);
    },
    onError: () => {
      setMessages((prev) => [
        ...prev,
        {
          id: `error-${Date.now()}`,
          role: "assistant",
          content: "Something went wrong. Please try again.",
          isError: true,
        },
      ]);
    },
  });

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, mutation.isPending]);

  const handleSend = () => {
    const text = input.trim();
    if (!text || mutation.isPending) return;

    setMessages((prev) => [
      ...prev,
      { id: `user-${Date.now()}`, role: "user", content: text },
    ]);
    setInput("");
    mutation.mutate({ text, convId: conversationId });
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div
      className="flex flex-col"
      style={{
        height: "calc(100dvh - 56px - env(safe-area-inset-bottom))",
        background: "var(--color-bg-base)",
      }}
    >
      {/* Header */}
      <div
        className="flex items-center justify-between gap-2 px-4 py-3 border-b"
        style={{ borderColor: "var(--color-border)", background: "var(--color-bg-subtle)" }}
      >
        <div className="flex items-center gap-2">
          <MessageCircle size={18} style={{ color: "var(--color-accent-blue)" }} />
          <span className="font-bold text-sm" style={{ color: "var(--color-fg-default)" }}>
            Portfolio Assistant
          </span>
          {conversationId && (
            <span className="text-[10px] px-1.5 py-0.5 rounded" style={{ background: "var(--color-bg-subtle)", color: "var(--color-fg-subtle)" }}>
              saved
            </span>
          )}
        </div>
        {messages.length > 0 && (
          <button
            onClick={handleNewChat}
            className="flex items-center gap-1 text-xs px-2.5 py-1.5 rounded-lg transition-colors"
            style={{ color: "var(--color-fg-muted)", background: "var(--color-bg-subtle)", border: "1px solid var(--color-border)" }}
            title="Start a new conversation"
          >
            <Plus size={12} />
            New
          </button>
        )}
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto px-4 py-4 space-y-4">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full gap-3 text-center">
            <MessageCircle size={40} style={{ color: "var(--color-fg-subtle)" }} />
            <p className="text-sm" style={{ color: "var(--color-fg-muted)" }}>
              Ask about your portfolio, strategies, or request an analysis.
            </p>
            <div className="flex flex-wrap gap-2 justify-center mt-2">
              {[
                "What's my portfolio looking like?",
                "Which positions need attention?",
                "Run a quick check on AAPL",
              ].map((suggestion) => (
                <button
                  key={suggestion}
                  onClick={() => {
                    setInput(suggestion);
                    inputRef.current?.focus();
                  }}
                  className="text-xs px-3 py-1.5 rounded-full border transition-colors"
                  style={{
                    borderColor: "var(--color-border)",
                    color: "var(--color-fg-muted)",
                    background: "var(--color-bg-subtle)",
                  }}
                >
                  {suggestion}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg) => (
          <div
            key={msg.id}
            className={clsx(
              "flex",
              msg.role === "user" ? "justify-end" : "justify-start"
            )}
          >
            <div
              className={clsx(
                "max-w-[85%] rounded-2xl px-4 py-2.5 text-sm leading-relaxed",
                msg.role === "user"
                  ? "rounded-br-sm"
                  : "rounded-bl-sm"
              )}
              style={
                msg.role === "user"
                  ? {
                      background: "var(--color-accent-blue)",
                      color: "#fff",
                    }
                  : msg.isError
                  ? {
                      background: "rgba(239,68,68,0.1)",
                      color: "var(--color-accent-red)",
                      border: "1px solid rgba(239,68,68,0.2)",
                    }
                  : {
                      background: "var(--color-bg-subtle)",
                      color: "var(--color-fg-default)",
                      border: "1px solid var(--color-border)",
                    }
              }
            >
              {msg.isError && (
                <AlertCircle size={14} className="inline mr-1 mb-0.5" />
              )}
              {/* Render as plain text — no client-side tool interpretation (D3.2) */}
              <span style={{ whiteSpace: "pre-wrap" }}>{msg.content}</span>
            </div>
          </div>
        ))}

        {mutation.isPending && (
