export interface AgentChatInput {
  userId: string;
  text: string;
  channel: ConversationChannel;
  conversationId?: string;
}

export interface AgentChatResult {
  replyText: string;
  conversationId: string;
  terminationReason: "model_final" | "max_turns" | "token_cap" | "points_budget_exhausted" | "error";
  totalCostUsd: number;
  turnCount: number;
}

