  if (!budget.allowed) {
    const convId = input.conversationId ?? `conv_budget_${Date.now()}`;
    return {
      replyText: "Your daily budget is exhausted. Try again after the budget window resets.",
      conversationId: convId,
      terminationReason: "points_budget_exhausted",
      totalCostUsd: 0,
      turnCount: 0,
